import android.content.Context
import android.content.SharedPreferences

class AuthManager private constructor(context: Context) {
    companion object {
        const val PREFERENCES_NAME = "auth_manager_prefs"
        const val AUTH_TOKEN_KEY = "auth_token"
        const val USER_ID_KEY = "user_id"

        fun getInstance(context: Context): AuthManager {
            return AuthManager(context)
        }
    }

    private var preferences: SharedPreferences

    init {
        preferences = context.getSharedPreferences(PREFERENCES_NAME, Context.MODE_PRIVATE)
    }

    fun saveAuthToken(authToken: String) {
        preferences.edit().putString(AUTH_TOKEN_KEY, authToken).apply()
    }

    fun saveUserId(userId: String) {
        preferences.edit().putString(USER_ID_KEY, userId).apply()
    }

    fun getAuthToken(): String? {
        return preferences.getString(AUTH_TOKEN_KEY, null)
    }

    fun getUserID(): String? {
        return preferences.getString(USER_ID_KEY, null)
    }

    fun clear() {
        preferences.edit().clear().apply()
    }
}